class Solution:
    def maximumCount(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def is_prime(x):
            if x < 2:
                return False
            for i in range(2, int(x**0.5) + 1):
                if x % i == 0:
                    return False
            return True

        prime_nums = set()
        for num in nums:
            if is_prime(num):
                prime_nums.add(num)

        prefix_sum = [0] * (len(nums) + 1)
        for i in range(len(nums)):
            prefix_sum[i + 1] = prefix_sum[i] + (1 if nums[i] in prime_nums else 0)

        result = []
        for idx, val in queries:
            nums[idx] = val
            left_sum = prefix_sum[idx]
            right_sum = prefix_sum[-1] - prefix_sum[idx + 1]
            result.append(left_sum + right_sum)

        return result
